import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import { useApp } from '../context/AppContext';

const Cart = () => {
  const { cart, removeFromCart, updateQuantity, cartTotal } = useApp();
  const navigate = useNavigate();

  if (cart.length === 0) {
    return (
      <div className="container cart-page">
        <motion.div 
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          style={{ textAlign: 'center' }}
        >
          <img 
            src="https://img.icons8.com/ios/200/2c3e50/shopping-bag.png" 
            alt="Empty cart" 
            style={{ opacity: 0.3, marginBottom: '20px' }}
          />
          <h1 style={{ marginBottom: '16px' }}>Savat bo'sh</h1>
          <p style={{ color: '#86868b', marginBottom: '24px' }}>Savatingizda hali mahsulotlar yo'q</p>
          <Link to="/products" className="btn">Mahsulotlarni ko'rish</Link>
        </motion.div>
      </div>
    );
  }

  return (
    <div className="container cart-page">
      <motion.h1 
        className="section-title"
        initial={{ x: -20, opacity: 0 }}
        animate={{ x: 0, opacity: 1 }}
      >
        Savat
      </motion.h1>

      {cart.map((item, index) => (
        <motion.div 
          key={`${item.id}-${item.variant}`}
          className="cart-item"
          initial={{ opacity: 0, x: -20 }}
          animate={{ opacity: 1, x: 0 }}
          transition={{ delay: index * 0.1 }}
        >
          <img 
            src={item.image || 'https://images.unsplash.com/photo-1523275335684-37898b6baf30?w=200'} 
            alt={item.name} 
            className="cart-item-image" 
          />
          <div className="cart-item-info">
            <h3>{item.name}</h3>
            <p>{item.brand}</p>
            {item.selectedColor && <p style={{ fontSize: '13px', color: '#86868b' }}>Rang: {item.selectedColor}</p>}
            {item.selectedSize && <p style={{ fontSize: '13px', color: '#86868b' }}>O'lcham: {item.selectedSize}</p>}
            <p style={{ fontWeight: 600, marginTop: '8px' }}>{item.price.toLocaleString()} so'm</p>
          </div>
          <div className="cart-item-controls">
            <button className="qty-btn" onClick={() => updateQuantity(item.id, item.variant, item.quantity - 1)}>-</button>
            <span style={{ minWidth: '30px', textAlign: 'center' }}>{item.quantity}</span>
            <button className="qty-btn" onClick={() => updateQuantity(item.id, item.variant, item.quantity + 1)}>+</button>
            <motion.button 
              className="btn btn-danger" 
              onClick={() => removeFromCart(item.id, item.variant)}
              whileTap={{ scale: 0.95 }}
              style={{ marginLeft: '12px' }}
            >
              O'chirish
            </motion.button>
          </div>
        </motion.div>
      ))}

      <motion.div 
        className="cart-total"
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ delay: 0.3 }}
      >
        Jami: <strong>{cartTotal.toLocaleString()} so'm</strong>
      </motion.div>

      <motion.div 
        style={{ textAlign: 'right' }}
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ delay: 0.4 }}
      >
        <button className="btn" onClick={() => navigate('/checkout')}>
          Buyurtma berish
        </button>
      </motion.div>
    </div>
  );
};

export default Cart;