import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { orders } from '../api';

const Orders = () => {
  const [ordersList, setOrdersList] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    orders.getAll()
      .then(res => setOrdersList(res.data))
      .catch(() => setOrdersList([]))
      .finally(() => setLoading(false));
  }, []);

  const getStatusClass = (status) => {
    switch(status) {
      case 'pending': return 'pending';
      case 'completed': return 'completed';
      case 'cancelled': return 'cancelled';
      default: return '';
    }
  };

  const getStatusLabel = (status) => {
    switch(status) {
      case 'pending': return 'Kutilmoqda';
      case 'completed': return 'Tugallangan';
      case 'cancelled': return 'Bekor qilingan';
      default: return status;
    }
  };

  if (loading) {
    return (
      <div className="container cart-page">
        <motion.div 
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          style={{ textAlign: 'center', padding: '60px' }}
        >
          <p>Yuklanmoqda...</p>
        </motion.div>
      </div>
    );
  }

  return (
    <div className="container cart-page">
      <motion.h1 
        className="section-title"
        initial={{ x: -20, opacity: 0 }}
        animate={{ x: 0, opacity: 1 }}
      >
        Buyurtmalarim
      </motion.h1>
      
      <div className="orders-list">
        {ordersList.length === 0 ? (
          <motion.div 
            className="empty"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
          >
            Buyurtmalar yo'q
          </motion.div>
        ) : ordersList.map((order, index) => (
          <motion.div 
            key={order.id} 
            className="order-card"
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: index * 0.1 }}
          >
            <div className="order-header">
              <span><strong>Buyurtma #{order.id}</strong></span>
              <span className={`order-status ${getStatusClass(order.status)}`}>{getStatusLabel(order.status)}</span>
            </div>
            <p style={{ marginBottom: '8px' }}>📦 {order.items || 'Mahsulotlar'}</p>
            <p style={{ marginBottom: '8px' }}>💰 Jami: <strong>{order.total_amount.toLocaleString()} so'm</strong></p>
            <p style={{ color: '#86868b', fontSize: '13px' }}>📅 Sana: {new Date(order.created_at).toLocaleDateString('uz-UZ')}</p>
          </motion.div>
        ))}
      </div>
    </div>
  );
};

export default Orders;