import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { motion } from 'framer-motion';
import { useApp } from '../context/AppContext';
import {
  Globe, Moon, Sun, Bell, Shield, Trash2,
  ChevronLeft, Check, Languages
} from 'lucide-react';

const LANGUAGES = [
  { code: 'uz', label: "O'zbek", flag: '🇺🇿', native: "O'zbek tili" },
  { code: 'ru', label: 'Русский', flag: '🇷🇺', native: 'Русский язык' },
  { code: 'en', label: 'English', flag: '🇬🇧', native: 'English' },
];

const Settings = () => {
  const { t, language, setLanguage, theme, toggleTheme, notifications, updateNotifications } = useApp();
  const [saved, setSaved] = useState(false);

  const handleSave = () => {
    setSaved(true);
    setTimeout(() => setSaved(false), 2500);
  };

  return (
    <div className="container settings-page">
      <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }}>
        {/* Header */}
        <div className="settings-header">
          <Link to="/profile" className="back-btn">
            <ChevronLeft size={20} />
          </Link>
          <h1 className="section-title">{t.settingsTitle}</h1>
        </div>

        {saved && (
          <motion.div
            className="message success"
            initial={{ opacity: 0, y: -10 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0 }}
          >
            {t.settingsSaved}
          </motion.div>
        )}

        <div className="settings-grid">
          {/* Language Section */}
          <motion.div
            className="settings-card"
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.1 }}
          >
            <div className="settings-card-header">
              <div className="settings-icon" style={{ background: '#EFF6FF', color: '#2563EB' }}>
                <Languages size={22} />
              </div>
              <div>
                <h3>{t.language}</h3>
                <p>{t.chooseLanguage}</p>
              </div>
            </div>

            <div className="language-options">
              {LANGUAGES.map(lang => (
                <motion.button
                  key={lang.code}
                  className={`lang-option ${language === lang.code ? 'active' : ''}`}
                  onClick={() => setLanguage(lang.code)}
                  whileHover={{ scale: 1.02 }}
                  whileTap={{ scale: 0.98 }}
                >
                  <span className="lang-flag">{lang.flag}</span>
                  <div className="lang-info">
                    <span className="lang-label">{lang.label}</span>
                    <span className="lang-native">{lang.native}</span>
                  </div>
                  {language === lang.code && (
                    <motion.div
                      className="lang-check"
                      initial={{ scale: 0 }}
                      animate={{ scale: 1 }}
                    >
                      <Check size={16} />
                    </motion.div>
                  )}
                </motion.button>
              ))}
            </div>
          </motion.div>

          {/* Appearance Section */}
          <motion.div
            className="settings-card"
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.2 }}
          >
            <div className="settings-card-header">
              <div className="settings-icon" style={{ background: '#FEF3C7', color: '#D97706' }}>
                {theme === 'dark' ? <Moon size={22} /> : <Sun size={22} />}
              </div>
              <div>
                <h3>{t.appearance}</h3>
                <p>{theme === 'dark' ? t.darkMode : t.lightMode}</p>
              </div>
            </div>

            <div className="theme-toggle-wrap">
              <div className="theme-option" onClick={() => theme !== 'light' && toggleTheme()}>
                <div className={`theme-preview light-preview ${theme === 'light' ? 'active' : ''}`}>
                  <Sun size={24} />
                  <span>{t.lightMode}</span>
                  {theme === 'light' && <div className="theme-check"><Check size={14} /></div>}
                </div>
              </div>
              <div className="theme-option" onClick={() => theme !== 'dark' && toggleTheme()}>
                <div className={`theme-preview dark-preview ${theme === 'dark' ? 'active' : ''}`}>
                  <Moon size={24} />
                  <span>{t.darkMode}</span>
                  {theme === 'dark' && <div className="theme-check"><Check size={14} /></div>}
                </div>
              </div>
            </div>
          </motion.div>

          {/* Notifications Section */}
          <motion.div
            className="settings-card"
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.3 }}
          >
            <div className="settings-card-header">
              <div className="settings-icon" style={{ background: '#ECFDF5', color: '#059669' }}>
                <Bell size={22} />
              </div>
              <div>
                <h3>{t.notifications}</h3>
                <p>Bildirishnoma sozlamalari</p>
              </div>
            </div>

            <div className="notification-options">
              <div className="notif-row">
                <div className="notif-info">
                  <span>{t.notifyOrders}</span>
                  <p>Buyurtma holati o'zgarganda xabar olish</p>
                </div>
                <label className="toggle-switch">
                  <input
                    type="checkbox"
                    checked={notifications.orders}
                    onChange={e => updateNotifications('orders', e.target.checked)}
                  />
                  <span className="toggle-slider"></span>
                </label>
              </div>
              <div className="notif-row">
                <div className="notif-info">
                  <span>{t.notifyOffers}</span>
                  <p>Yangi chegirmalar va aktsiyalar</p>
                </div>
                <label className="toggle-switch">
                  <input
                    type="checkbox"
                    checked={notifications.offers}
                    onChange={e => updateNotifications('offers', e.target.checked)}
                  />
                  <span className="toggle-slider"></span>
                </label>
              </div>
              <div className="notif-row">
                <div className="notif-info">
                  <span>{t.notifyNews}</span>
                  <p>Sayt yangiliklari va e'lonlar</p>
                </div>
                <label className="toggle-switch">
                  <input
                    type="checkbox"
                    checked={notifications.news}
                    onChange={e => updateNotifications('news', e.target.checked)}
                  />
                  <span className="toggle-slider"></span>
                </label>
              </div>
            </div>
          </motion.div>

          {/* Privacy Section */}
          <motion.div
            className="settings-card danger-card"
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.4 }}
          >
            <div className="settings-card-header">
              <div className="settings-icon" style={{ background: '#FEE2E2', color: '#DC2626' }}>
                <Shield size={22} />
              </div>
              <div>
                <h3>{t.privacy}</h3>
                <p>Hisob xavfsizligi</p>
              </div>
            </div>

            <div className="danger-zone">
              <div className="danger-row">
                <div>
                  <span className="danger-title">{t.deleteAccount}</span>
                  <p className="danger-desc">{t.deleteAccountDesc}</p>
                </div>
                <button
                  className="btn btn-danger"
                  onClick={() => {
                    if (window.confirm('Haqiqatan ham hisobingizni o\'chirmoqchimisiz? Bu amalni ortga qaytarib bo\'lmaydi!')) {
                      alert('Bu funksiya admin tomonidan boshqariladi.');
                    }
                  }}
                >
                  <Trash2 size={16} />
                  {t.deleteAccount}
                </button>
              </div>
            </div>
          </motion.div>
        </div>

        <motion.div
          style={{ textAlign: 'center', marginTop: '32px' }}
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ delay: 0.5 }}
        >
          <motion.button
            className="btn btn-primary"
            style={{ minWidth: '200px' }}
            onClick={handleSave}
            whileHover={{ scale: 1.03 }}
            whileTap={{ scale: 0.97 }}
          >
            <Check size={18} /> {t.saveSettings}
          </motion.button>
        </motion.div>
      </motion.div>
    </div>
  );
};

export default Settings;
