import React, { useState, useEffect } from 'react';
import { Navigate } from 'react-router-dom';
import { Link, Routes, Route, useLocation } from 'react-router-dom';
import { motion } from 'framer-motion';
import { useApp } from '../../context/AppContext';
import { stats } from '../../api';
import AdminProducts from './Products';
import AdminCategories from './Categories';
import AdminOrders from './Orders';

const AdminDashboard = () => {
  const { user, loading } = useApp();
  const location = useLocation();
  const [statsData, setStatsData] = useState(null);

  useEffect(() => {
    if (user?.role === 'admin') {
      stats.get()
        .then(res => setStatsData(res.data))
        .catch(() => {});
    }
  }, [user]);

  if (loading) {
    return (
      <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '100vh' }}>
        <p>Yuklanmoqda...</p>
      </div>
    );
  }
  
  if (!user || user.role !== 'admin') {
    return <Navigate to="/" />;
  }

  const isActive = (path) => location.pathname === path;

  return (
    <div className="admin-layout">
      <div className="sidebar">
        <h2>Admin Panel</h2>
        <Link to="/admin" className={isActive('/admin') ? 'active' : ''}>
          <img src="https://img.icons8.com/ios/50/ffffff/dashboard.png" alt="" />
          Bosh sahifa
        </Link>
        <Link to="/admin/products" className={isActive('/admin/products') ? 'active' : ''}>
          <img src="https://img.icons8.com/ios/50/ffffff/product.png" alt="" />
          Mahsulotlar
        </Link>
        <Link to="/admin/categories" className={isActive('/admin/categories') ? 'active' : ''}>
          <img src="https://img.icons8.com/ios/50/ffffff/category.png" alt="" />
          Kategoriyalar
        </Link>
        <Link to="/admin/orders" className={isActive('/admin/orders') ? 'active' : ''}>
          <img src="https://img.icons8.com/ios/50/ffffff/order.png" alt="" />
          Buyurtmalar
        </Link>
        <Link to="/">
          <img src="https://img.icons8.com/ios/50/ffffff/home.png" alt="" />
          Saytga qaytish
        </Link>
      </div>
      
      <div className="admin-content">
        <div className="admin-header">
          <h1>Admin Dashboard</h1>
          <button 
            className="btn btn-secondary" 
            onClick={async () => {
              try {
                const { demo } = await import('../../api');
                await demo.seed();
                alert('Demo ma`lumotlar muvaffaqiyatli yaratildi! Sahifani yangilang.');
                window.location.reload();
              } catch (e) {
                alert('Xatolik: ' + e.message);
              }
            }}
          >
            Demo Ma'lumot Qushish (Reklama uchun)
          </button>
        </div>
        
        {statsData && (
          <motion.div 
            className="stats-grid"
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
          >
            <div className="stat-card">
              <h3>{statsData.totalProducts}</h3>
              <p>Mahsulotlar</p>
            </div>
            <div className="stat-card">
              <h3>{statsData.totalOrders}</h3>
              <p>Buyurtmalar</p>
            </div>
            <div className="stat-card">
              <h3>{statsData.totalRevenue.toLocaleString()}</h3>
              <p>Daromad (so'm)</p>
            </div>
            <div className="stat-card">
              <h3>{statsData.pendingOrders}</h3>
              <p>Kutilayotgan</p>
            </div>
          </motion.div>
        )}
        
        <Routes>
          <Route path="/" element={
            <motion.div 
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
            >
              <h2>Xush kelibsiz, Admin!</h2>
              <p style={{ color: '#86868b', marginTop: '12px' }}>Yuqoridagi menyudan bo'limni tanlang.</p>
            </motion.div>
          } />
          <Route path="/products" element={<AdminProducts />} />
          <Route path="/categories" element={<AdminCategories />} />
          <Route path="/orders" element={<AdminOrders />} />
        </Routes>
      </div>
    </div>
  );
};

export default AdminDashboard;